if (response.status === 200) {
  console.log('Profile updated');
} else {
  throw new Error(`Profile update failed: ${response.status}`);
}

if (response.status === 200) {
  const body = response.json();
  console.log(`Logged in as: ${body.name} (${body.email})`);
} else if (response.status === 401) {
  throw new Error('Not authenticated — run Login first');
}

if (response.status === 204 || response.status === 200) {
  console.log('Product deleted successfully');
} else if (response.status === 404) {
  console.log('Product already deleted or not found');
} else {
  throw new Error(`Delete failed: ${response.status}`);
}

if (response.status === 200) {
  const body = response.json();
  console.log(`Patched product — new price: $${body.price}`);
} else {
  throw new Error(`Patch failed: ${response.status}`);
}

if (response.status === 200) {
  const body = response.json();
  console.log(`Updated product #${body.id}`);
} else if (response.status === 404) {
  throw new Error('Product not found — cannot update');
} else {
  throw new Error(`Update failed: ${response.status}`);
}

const body = response.json();

if (response.status === 201) {
  emit('productId', String(body.id));
  console.log(`Created product #${body.id}: ${body.name}`);
} else if (response.status === 409) {
  console.log(`Product already exists: ${body.message}`);
} else {
  throw new Error(`Create failed: ${response.status} — ${JSON.stringify(body)}`);
}

const body = response.json();

if (response.status === 200) {
  emit('productName', body.name);
  emit('productPrice', String(body.price));
  console.log(`Product: ${body.name} — $${body.price}`);
} else if (response.status === 404) {
  console.log('Product not found');
} else {
  throw new Error(`Unexpected status: ${response.status}`);
}

// Validate list response
const body = response.json();

if (response.status !== 200) {
  throw new Error(`List products failed: ${response.status}`);
}

if (!Array.isArray(body.data)) {
  throw new Error('Expected data array in response');
}

console.log(`Got ${body.data.length} products (total: ${body.total})`);

if (response.status === 200) {
  const body = response.json();
  emit('authToken', body.token);
  console.log('Token refreshed');
}

// Extract and store the auth token
const body = response.json();

if (response.status === 200 && body.token) {
  emit('authToken', body.token);
  emit('userId', body.user.id);
  console.log('Login successful, token stored');
} else {
  throw new Error(`Login failed: ${response.status} — ${body.message}`);
}

// Verify the service is healthy
if (response.status !== 200) {
  throw new Error(`Health check failed: ${response.status}`);
}

const body = response.json();
if (body.status !== 'ok') {
  throw new Error(`Unexpected health status: ${body.status}`);
}

console.log('Health check passed');

